       case 'predict':
-        return this.runPredictWorker();
+        return this.runPredictWorkerLocal();
       case 'document':
-        return this.runDocumentWorker();
+        return this.runDocumentWorkerLocal();
+      case 'ultralearn':
+        return this.runUltralearnWorkerLocal();
+      case 'refactor':
+        return this.runRefactorWorkerLocal();
